package main

import (
	"math"
)

func generateSieve(max int) []bool {
	sieve := make([]bool, max+1)
	for i := 0; i <= max; i++ {
		sieve[i] = true
	}
	sieve[0] = false
	sieve[1] = false
	for i := 2; i*i <= max; i++ {
		if sieve[i] {
			for j := i * i; j <= max; j += i {
				sieve[j] = false
			}
		}
	}
	return sieve
}

func solve(nums []int64) int64 {
	n := len(nums)
	if n == 0 {
		return 0
	}
	maxIdx := n - 1
	sieve := generateSieve(maxIdx)
	var sumA, sumB int64
	for i := 0; i < n; i++ {
		if sieve[i] {
			sumA += nums[i]
		} else {
			sumB += nums[i]
		}
	}
	diff := sumA - sumB
	if diff < 0 {
		diff = -diff
	}
	return diff
}
